package Operators;

public class Relational {
	
	//(==,!=,>,<,>=,<=)

	

		public static void main(String[] args) {
			// TODO Auto-generated method stub
			int a=10;
			int b=20;
			int c=10;
			System.out.println(a==b);//false
			System.out.println(a!=b);//true
			System.out.println(a<b);//true
			System.out.println(b<a);//false
			System.out.println(b<a);//false
			System.out.println(a<=c);//true
			System.out.println(a>=b);//false

		}

	}
